import React, { useCallback, useState } from 'react';
import { Button, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import { MONTH_OPTIONS, yearOptions } from '../../constants/periodFilter';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import df from '../../styles/documentForm.module.css';

export interface HrPeriodActionPanelProps {
  title: string;
  icon: string;
  description?: string;
  testIdPrefix?: string;
  periodSectionTitle?: string;
  runLabel?: string;
  postLabel?: string;
  onRun: (month: number, year: number) => Promise<unknown>;
  onPost?: (month: number, year: number) => Promise<unknown>;
  getStatus?: (month: number, year: number) => Promise<string | null>;
  onActionComplete?: () => void;
  renderExtra?: (ctx: { month: number; year: number }) => React.ReactNode;
  runPermitted?: boolean;
  postPermitted?: boolean;
}

export const HrPeriodActionPanel: React.FC<HrPeriodActionPanelProps> = ({
  title,
  icon,
  description,
  testIdPrefix = 'ns-period-action',
  periodSectionTitle = 'Kỳ thực hiện',
  runLabel = 'Thực hiện',
  postLabel = 'Xác nhận',
  onRun,
  onPost,
  getStatus,
  onActionComplete,
  renderExtra,
  runPermitted = true,
  postPermitted = true,
}) => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);
  const [statusLabel, setStatusLabel] = useState<string | null>(null);
  const [statusLoading, setStatusLoading] = useState(false);

  const m = Number(month);
  const y = Number(year);
  const periodKey = `${month}-${year}`;

  const refreshStatus = useCallback(() => {
    if (!getStatus) return;
    setStatusLoading(true);
    getStatus(m, y)
      .then(setStatusLabel)
      .catch(() => setStatusLabel(null))
      .finally(() => setStatusLoading(false));
  }, [getStatus, m, y]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (cancelled || !getStatus) return;
      setStatusLoading(true);
      getStatus(m, y)
        .then(label => {
          if (!cancelled) setStatusLabel(label);
        })
        .catch(() => {
          if (!cancelled) setStatusLabel(null);
        })
        .finally(() => {
          if (!cancelled) setStatusLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [getStatus, periodKey, m, y]);

  const handleActionResult = () => {
    refreshStatus();
    onActionComplete?.();
  };

  const handleRun = async () => {
    setRunning(true);
    try {
      await onRun(m, y);
      handleActionResult();
      dispatchAppToast(dispatch, { message: `${runLabel} thành công`, type: 'success' });
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, `${runLabel} thất bại`),
        type: 'error',
      });
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    if (!onPost) return;
    setPosting(true);
    try {
      await onPost(m, y);
      handleActionResult();
      dispatchAppToast(dispatch, { message: `${postLabel} thành công`, type: 'success' });
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, `${postLabel} thất bại`),
        type: 'error',
      });
    } finally {
      setPosting(false);
    }
  };

  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;

  return (
    <div className={df.page} data-testid={tid('page')}>
      <div className={df.stickyTop}>
        <div className={df.pageHeader}>
          <div className={df.titleGroup}>
            <div>
              <div className={df.titleRow}>
                <h1 className={df.title} data-testid={tid('title')}>
                  <i className={`fas ${icon}`} style={{ marginRight: 8 }} />
                  {title}
                </h1>
              </div>
              {description && (
                <p
                  style={{
                    margin: '4px 0 0',
                    fontSize: 13,
                    color: 'var(--color-text-secondary, #6c757d)',
                  }}
                >
                  {description}
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className={df.section} data-testid={tid('section-period')}>
        <h2 className={df.sectionTitle}>{periodSectionTitle}</h2>
        {getStatus && (
          <p
            data-testid={tid('status')}
            style={{ margin: '0 0 12px', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}
          >
            {statusLoading ? 'Đang tải trạng thái…' : (statusLabel ?? '—')}
          </p>
        )}
        <div className={df.row4}>
          <div className={df.field} data-testid={tid('field-month')}>
            <label className={df.label}>Tháng</label>
            <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
          </div>
          <div className={df.field} data-testid={tid('field-year')}>
            <label className={df.label}>Năm</label>
            <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
          </div>
          <div className={df.field} aria-hidden />
          <div className={df.field} aria-hidden />
        </div>
        <div
          className={df.footer}
          style={{ marginTop: 12, padding: 0, border: 'none', background: 'transparent' }}
        >
          {runPermitted && (
            <Button
              variant="primary"
              data-testid={tid('run-btn')}
              onClick={handleRun}
              loading={running}
              disabled={running || posting}
            >
              {runLabel}
            </Button>
          )}
          {onPost && postPermitted && (
            <Button
              variant="secondary"
              data-testid={tid('post-btn')}
              onClick={handlePost}
              loading={posting}
              disabled={running || posting}
            >
              {postLabel}
            </Button>
          )}
        </div>
      </div>

      {renderExtra?.({ month: m, year: y })}
    </div>
  );
};
